import{_ as t,o as a,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"187. Best Practice Royal Children S Hospital","description":"","frontmatter":{"title":"187. Best Practice Royal Children S Hospital","eba":"Mental Health Services 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/preliminary/187-best-practice-royal-children-s-hospital.md","filePath":"ebas/mental-health/management-admin/preliminary/187-best-practice-royal-children-s-hospital.md"}'),i={name:"ebas/mental-health/management-admin/preliminary/187-best-practice-royal-children-s-hospital.md"};function n(o,e,p,l,c,h){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_187-best-practice-royal-children-s-hospital" tabindex="-1">187. Best Practice Royal Children S Hospital <a class="header-anchor" href="#_187-best-practice-royal-children-s-hospital" aria-label="Permalink to &quot;187. Best Practice Royal Children S Hospital&quot;">​</a></h1><p>This clause only applies to Management and Administrative Officers at Royal Children’s Hospital classified under Part 2 of <a href="/eba/ebas/mental-health/schedules/07-management-and-administrative-officers-classifications.html">Schedule 7</a> of this Agreement.</p><p><strong>187.1</strong> The parties agree that a process, which focuses on sustaining improvements in productivity, will enable the health services to compete in the market more effectively.</p><p><strong>187.2</strong> The following principles and processes underlie the “best practice” approach of the health services:</p><p><strong>(a)</strong> Understanding and commitment to achieving world class performance in all aspects of the health services’ operations.</p><p><strong>(b)</strong> Continuous improvement in the quality, efficiency, effectiveness and cost of health services is an ongoing process essential to the achievement of best practice.</p><p><strong>187.3</strong> The parties agree that there will be commitment and support given to the ongoing process of continuous improvement, including:</p><p><strong>(a)</strong> innovation</p><p><strong>(b)</strong> evaluating opportunities</p><p><strong>(c)</strong> productivity</p><p><strong>(d)</strong> cost effectiveness</p><p><strong>(e)</strong> benchmarking</p><p><strong>(f)</strong> expansion opportunities</p><p><strong>(g)</strong> flexibilities, where Employees may be required to work between health services, when required</p><p><strong>(h)</strong> workplace agreements to support agreed best practice</p><p><strong>(i)</strong> work on major projects linked to the health services’ priorities; and</p><p><strong>(j)</strong> service/department reviews and the development of agreed performance indicators.</p><p><strong>187.4</strong> It is jointly recognised that performance measurement will make it easier to set goals for strategic planning, and for establishing targets at the departmental level. Across all levels of the health services, strategic reviews will generate performance data, which may identify potential improvement, the manner in which those improvements will be achieved and monitored.</p><p><strong>187.5</strong> To ensure competitiveness, the health services must adopt a comprehensive approach to the measurement of productivity, whereby a broad range of performance indicators are kept for the health services and linked to indicators in each department.</p>',19)])])}const g=t(i,[["render",n]]);export{d as __pageData,g as default};
